"use strict";
const KEY="marawa.prototype.v1", form=document.querySelector("#chat-form"), input=document.querySelector("#message-input"), status=document.querySelector("#status"), transcript=document.querySelector("#transcript"), reset=document.querySelector("#new-conversation");
let state=null, expired=false;
const headers=()=>({"Content-Type":"application/json","Origin":location.origin,"X-Server-Generation":state?.server_generation||""});
function save(){if(state){state.transcript=state.transcript.slice(-100);localStorage.setItem(KEY,JSON.stringify(state));}}
function bubble(item){const el=document.createElement("div");el.className=`bubble ${item.role}`;el.textContent=item.text;el.dataset.deliveryState=item.delivery_state;transcript.append(el);}
function hydrate(){try{const x=JSON.parse(localStorage.getItem(KEY));if(x?.schema_version!==1||!Array.isArray(x.transcript))return;state=x;state.transcript.slice(-100).forEach(bubble);validate();}catch{localStorage.removeItem(KEY);}}
async function createSession(){const r=await fetch("/api/prototype/sessions",{method:"POST",headers:headers(),body:"{}"}),j=await r.json();state={schema_version:1,...j.data,transcript:[]};save();return state;}
async function validate(){const r=await fetch(`/api/prototype/sessions/${state.session_id}`,{headers:headers()});if(!r.ok){expired=true;input.disabled=true;status.textContent="Sesi lama berakhir. Mulai percakapan baru.";}}
form.addEventListener("submit",async e=>{e.preventDefault();const text=input.value.trim();if(!text||expired)return;if(!state)await createSession();const item={id:crypto.randomUUID(),role:"user",text,actions:[],created_at:new Date().toISOString(),delivery_state:"pending"};state.transcript.push(item);bubble(item);save();input.value="";status.textContent="Memproses…";try{const r=await fetch(`/api/prototype/sessions/${state.session_id}/messages`,{method:"POST",headers:headers(),body:JSON.stringify({message_id:item.id,state_version:state.state_version,text})}),j=await r.json();if(!r.ok)throw new Error(j.error?.code);item.delivery_state="sent";state.state_version=j.data.state_version;const answer={id:j.data.assistant.id,role:"assistant",text:j.data.assistant.text,actions:j.data.assistant.actions,created_at:new Date().toISOString(),delivery_state:"sent"};state.transcript.push(answer);bubble(answer);status.textContent="Siap";}catch{item.delivery_state="failed";status.textContent="Pesan gagal dikirim. Coba lagi.";}save();input.focus();});
reset.addEventListener("click",async()=>{if(state?.transcript.length&&!confirm("Mulai percakapan baru?"))return;if(state)await fetch(`/api/prototype/sessions/${state.session_id}`,{method:"DELETE",headers:headers()});localStorage.removeItem(KEY);state=null;expired=false;transcript.textContent="";input.disabled=false;status.textContent="Percakapan baru siap.";input.focus();});
hydrate();
